import React, { useState, useEffect } from 'react';
import axios from 'axios';
import QRCode from 'react-qr-code';
import './App.css';

const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:3001/api';

interface Order {
  id: string;
  customerName: string;
  items: string;
  total: number;
  status: string;
  createdAt: string;
}

interface Product {
  id: string;
  name: string;
  price: number;
  stock: number;
  description: string;
}

interface Stats {
  totalOrders: number;
  totalRevenue: number;
  pendingOrders: number;
  totalProducts: number;
}

function App() {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [orders, setOrders] = useState<Order[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [stats, setStats] = useState<Stats>({
    totalOrders: 0,
    totalRevenue: 0,
    pendingOrders: 0,
    totalProducts: 0
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fetchOrders = async () => {
    try {
      setLoading(true);
      setError(null);
      const response = await axios.get(`${API_BASE_URL}/orders`);
      setOrders(response.data || []);
    } catch (error) {
      console.error('Error fetching orders:', error);
      setError('Failed to fetch orders');
      setOrders([]);
    } finally {
      setLoading(false);
    }
  };

  const fetchProducts = async () => {
    try {
      setLoading(true);
      setError(null);
      const response = await axios.get(`${API_BASE_URL}/products`);
      setProducts(response.data || []);
    } catch (error) {
      console.error('Error fetching products:', error);
      setError('Failed to fetch products');
      setProducts([]);
    } finally {
      setLoading(false);
    }
  };

  const fetchStats = async () => {
    try {
      const response = await axios.get(`${API_BASE_URL}/stats`);
      setStats(response.data || stats);
    } catch (error) {
      console.error('Error fetching stats:', error);
      // Use mock data if API fails
      setStats({
        totalOrders: orders.length,
        totalRevenue: orders.reduce((sum, order) => sum + order.total, 0),
        pendingOrders: orders.filter(order => order.status === 'pending').length,
        totalProducts: products.length
      });
    }
  };

  useEffect(() => {
    if (activeTab === 'orders') {
      fetchOrders();
    } else if (activeTab === 'products') {
      fetchProducts();
    } else if (activeTab === 'dashboard') {
      fetchOrders();
      fetchProducts();
      fetchStats();
    }
  }, [activeTab]);

  const updateOrderStatus = async (orderId: string, status: string) => {
    try {
      await axios.patch(`${API_BASE_URL}/orders/${orderId}`, { status });
      fetchOrders();
      if (activeTab === 'dashboard') fetchStats();
    } catch (error) {
      console.error('Error updating order:', error);
      setError('Failed to update order status');
    }
  };

  const renderDashboard = () => (
    <div className="dashboard-section">
      <h2>Dashboard Overview</h2>
      <div className="stats-grid">
        <div className="stat-card">
          <h3>Total Orders</h3>
          <div className="stat-value">{stats.totalOrders}</div>
        </div>
        <div className="stat-card">
          <h3>Total Revenue</h3>
          <div className="stat-value">${stats.totalRevenue.toFixed(2)}</div>
        </div>
        <div className="stat-card">
          <h3>Pending Orders</h3>
          <div className="stat-value">{stats.pendingOrders}</div>
        </div>
        <div className="stat-card">
          <h3>Total Products</h3>
          <div className="stat-value">{stats.totalProducts}</div>
        </div>
      </div>

      <div className="recent-orders">
        <h3>Recent Orders</h3>
        <div className="orders-grid">
          {orders.slice(0, 4).map(order => (
            <div key={order.id} className="order-card">
              <h4>Order #{order.id}</h4>
              <p><strong>Customer:</strong> {order.customerName}</p>
              <p><strong>Total:</strong> ${order.total}</p>
              <p><strong>Status:</strong> <span className={`status ${order.status}`}>{order.status}</span></p>
            </div>
          ))}
        </div>
      </div>
    </div>
  );

  return (
    <div className="App">
      <header className="App-header">
        <h1>🛍️ E-commerce Admin Dashboard</h1>
        <nav>
          <button 
            className={activeTab === 'dashboard' ? 'active' : ''}
            onClick={() => setActiveTab('dashboard')}
          >
            📊 Dashboard
          </button>
          <button 
            className={activeTab === 'orders' ? 'active' : ''}
            onClick={() => setActiveTab('orders')}
          >
            📦 Orders
          </button>
          <button 
            className={activeTab === 'products' ? 'active' : ''}
            onClick={() => setActiveTab('products')}
          >
            🛒 Products
          </button>
          <button 
            className={activeTab === 'qr' ? 'active' : ''}
            onClick={() => setActiveTab('qr')}
          >
            📱 QR Code
          </button>
        </nav>
      </header>

      <main className="App-main">
        {loading && <div className="loading">⏳ Loading...</div>}
        {error && <div className="error">❌ {error}</div>}

        {activeTab === 'dashboard' && renderDashboard()}

        {activeTab === 'orders' && (
          <div className="orders-section">
            <h2>Orders Management</h2>
            <div className="orders-grid">
              {orders.length === 0 ? (
                <div className="no-data">No orders found</div>
              ) : (
                orders.map(order => (
                  <div key={order.id} className="order-card">
                    <h3>Order #{order.id}</h3>
                    <p><strong>Customer:</strong> {order.customerName}</p>
                    <p><strong>Items:</strong> {order.items}</p>
                    <p><strong>Total:</strong> ${order.total}</p>
                    <p><strong>Status:</strong> <span className={`status ${order.status}`}>{order.status}</span></p>
                    <p><strong>Date:</strong> {new Date(order.createdAt).toLocaleDateString()}</p>
                    <div className="order-actions">
                      <button onClick={() => updateOrderStatus(order.id, 'processing')}>
                        🔄 Processing
                      </button>
                      <button onClick={() => updateOrderStatus(order.id, 'shipped')}>
                        🚚 Shipped
                      </button>
                      <button onClick={() => updateOrderStatus(order.id, 'delivered')}>
                        ✅ Delivered
                      </button>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        )}

        {activeTab === 'products' && (
          <div className="products-section">
            <h2>Products Management</h2>
            <div className="products-grid">
              {products.length === 0 ? (
                <div className="no-data">No products found</div>
              ) : (
                products.map(product => (
                  <div key={product.id} className="product-card">
                    <h3>{product.name}</h3>
                    <p><strong>Price:</strong> ${product.price}</p>
                    <p><strong>Stock:</strong> {product.stock}</p>
                    <p><strong>Description:</strong> {product.description}</p>
                    <div className="product-actions">
                      <button>✏️ Edit</button>
                      <button>🗑️ Delete</button>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        )}

        {activeTab === 'qr' && (
          <div className="qr-section">
            <h2>QR Code Generator</h2>
            <div className="qr-container">
              <QRCode 
                value="http://localhost:3000" 
                size={256}
                level="H"
              />
              <p>📱 Scan to access the store</p>
              <p className="qr-url">http://localhost:3000</p>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
